const output = $input.item.json.stdout || '';
const stderr = $input.item.json.stderr || '';
const exitCode = $input.item.json.exitCode || 0;

const passed = (output.match(/Passed: ([^\n]+)/)?.[1] || '').split(',').map(s => s.trim()).filter(Boolean);
const failed = (output.match(/Failed: ([^\n]+)/)?.[1] || '').split(',').map(s => s.trim()).filter(Boolean);
const triggers = (output.match(/TRIGGER EVENT DETECTED/g) || []).length;

return [{ json: { exitCode, passed, failed, triggers, hasErrors: failed.length > 0 || exitCode !== 0 } }];

